
let computerSound = null;

async function playSound(type) {
  const sounds = {
    COMPUTER: 'computerWorking.mp3',
    WARNING: 'computerWarning.mp3',
	ERROR: 'computerError.mp3',
    REPORT: 'computerPrintingScreen.mp3',
    BEEP: 'computerBeep.mp3',
    KEY: 'computerKey.mp3'	
	};

  const audioFile = sounds[type];
  
  if (type === 'COMPUTER') {
    // Se já está tocando, não reinicia
    if (computerSound) return;
    computerSound = new Audio(audioFile);
    computerSound.loop = true;
    computerSound.play();
  } else {
    // Sons únicos
    const sound = new Audio(audioFile);
    sound.play();
  }
}

async function sha256(text) {
        const encoder = new TextEncoder();
        const data = encoder.encode(text);
        const hashBuffer = await crypto.subtle.digest('SHA-256', data);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
        return hashHex;
    }
	
