// Atualiza texto digitado
hiddenInput.addEventListener('input', (e) => {
    commandInput.textContent = e.target.value;
});

// Trata teclas especiais
hiddenInput.addEventListener('keydown', (e) => {
    playSound('KEY');
	if ( boot == true ) {
   		 processaBoot();
		 e.key = null;
		 return;
	     }
	if (e.key === 'Backspace') {
        e.preventDefault();
        const atual = commandInput.textContent;
        commandInput.textContent = atual.slice(0, -1);
        hiddenInput.value = commandInput.textContent;
    }
    if (e.key === 'Enter') {
		  const command = commandInput.innerText
          hiddenInput.value = ''
		  commandInput.innerHTML = ''
 		  // reprint the entered command
 		  output.innerHTML += '<strong>' + command + '</strong><br>'	     
		  if ( login == true ) {
		    if ( senha == false ) 
		         processLogin(command)
		    else processSenha(command)
	        }
	      else
          if ( consulta == true ) {
		       processConsultaPessoa(command)
			   }
	      else
          if ( consultaID == true ) {
		       processConsultaID(command)
			   }
	      else
	      if ( consultaInqueritos == true ) {
		       processInqueritos(command)
	           }
		  else 
		  if ( consultaATImpressoes == true ) {
			   processATImpressoes(command)
			   }
		  else 
		  if ( consultaATID == true ) {
			   processATPorID(command)
			   }
		  else 
		  if ( consultAlertas == true ) {
			   processAlertas(command)
			   }
		  else 
		  if ( consultaOperacoes == true ) {
			   processOperacoes(command)
			   }
		  else 
		  if ( consultaProjetos == true ) {
			   processProjetos(command)
			   }
	      else 
		      writeText(output, execute(command))
    }

});
